def anagram_gruplama(kelimeler):
    """
    Bir kelime listesini anagram gruplarına ayırır.

    Args:
        kelimeler: Anagram gruplarına ayrılacak kelimelerin listesi.

    Returns:
        Anagram gruplarının bir listesi.
    """

    anagram_gruplari = {}
    for kelime in kelimeler:
        siralanmis_kelime = "".join(sorted(kelime))
        if siralanmis_kelime in anagram_gruplari:
            anagram_gruplari[siralanmis_kelime].append(kelime)
        else:
            anagram_gruplari[siralanmis_kelime] = [kelime]

    return list(anagram_gruplari.values())

if __name__ == '__main__':
    kelimeler = ["eat", "tea", "tan", "ate", "nat", "bat"]
    anagram_gruplari = anagram_gruplama(kelimeler)
    print(anagram_gruplari)
